actions.script:
import java.security.MessageDigest
def digest = MessageDigest.getInstance("SHA-256")
def hashBytes = digest.digest(rawContent.trim().getBytes("UTF-8"))
context.contentHash = hashBytes.collect { String.format("%02x", it) }.join()

def existing = ec.entity.find("trade.swift.InboundSwiftRaw").condition("contentHash", context.contentHash).one()
if (existing) {
    context.isDuplicate = true
    context.rawMessageId = existing.rawMessageId
    context.parseSuccess = (existing.parseStatusEnumId == 'PARSE_SUCCESS')
    return
}

import com.prowidesoftware.swift.model.SwiftMessage
ec.logger.info("INGEST_DEBUG: Attempting to parse SWIFT content (length: ${rawContent?.length()})")
try {
    def sm = SwiftMessage.parse(rawContent)
    context.messageType = sm.getType()
    ec.logger.info("INGEST_DEBUG: Parsed message type: ${context.messageType}")
    def block1 = sm.getBlock1()
    ec.logger.info("INGEST_DEBUG: Block1: ${block1 != null}")
    def logicalTerminal = block1?.getLogicalTerminal()
    ec.logger.info("INGEST_DEBUG: LogicalTerminal: ${logicalTerminal}")
    def senderBic = logicalTerminal?.substring(0, 8) ?: "UNKNOWN"

    def block4 = sm.getBlock4()
    ec.logger.info("INGEST_DEBUG: Block4: ${block4 != null}")
    def tag20 = block4?.getTagValue("20")
    ec.logger.info("INGEST_DEBUG: Tag 20: ${tag20}")

    def block2 = sm.getBlock2()
    ec.logger.info("INGEST_DEBUG: Block2: ${block2 != null}")
    def dateStr = ""
    if (block2 != null) {
        try {
            if (block2.isOutput()) dateStr = block2.getReceiverOutputTime()
            else if (block2.isInput()) dateStr = "" // Input block 2 has no time
        } catch (Throwable t) { ec.logger.warn("Could not get time from block 2: ${t.message}") }
    }
    ec.logger.info("INGEST_DEBUG: DateStr: ${dateStr}")

    context.swiftHeaderKey = "${senderBic}|${context.messageType}|${tag20 ?: ''}|${dateStr}"
    ec.logger.info("INGEST_DEBUG: SwiftHeaderKey: ${context.swiftHeaderKey}")

    context.parseSuccess = true
    ec.logger.info("INGEST_DEBUG: Parse process completed successfully")
} catch (Throwable e) {
    context.parseSuccess = false
    context.parseErrorText = e.getMessage()
    ec.logger.error("INGEST_ERROR: Failed to parse SWIFT message: ${e.getMessage()}", e)
}

ec.logger.info("INGEST_DEBUG: Creating InboundSwiftRaw, success: ${context.parseSuccess}")
def rawOut = ec.service.sync().name("create#trade.swift.InboundSwiftRaw").parameters([
    contentHash: context.contentHash, swiftHeaderKey: context.swiftHeaderKey,
    messageType: context.messageType, rawContent: rawContent,
    sourceChannel: sourceChannel, sourceFileName: sourceFileName,
    receivedTimestamp: ec.user.nowTimestamp,
    parseStatusEnumId: context.parseSuccess ? "PARSE_SUCCESS" : "PARSE_FAILED",
    parseErrorText: context.parseErrorText
]).call()
context.rawMessageId = rawOut.rawMessageId
context.isDuplicate = false

if (context.parseSuccess && !skipCorrelation) {
    ec.logger.info("INGEST_DEBUG: Triggering async correlation for rawMessageId: ${context.rawMessageId}")
    ec.service.async().name("trade.swift.InboundCorrelationServices.correlate#SwiftMessage").parameter("rawMessageId", context.rawMessageId).call()
}

def inDir = new File(inboundDir)
if (!inDir.exists()) { ec.logger.warn("Inbound dir not found: ${inboundDir}"); return }

def processedDir = new File("${archiveDir}/processed")
def errorDir = new File("${archiveDir}/error")
def duplicateDir = new File("${archiveDir}/duplicate")
[processedDir, errorDir, duplicateDir].each { if (!it.exists()) it.mkdirs() }

inDir.listFiles({ f -> f.name.endsWith(".txt") } as FileFilter)?.each { file ->
    // Write-complete check: file size stable for 2 seconds
    long size1 = file.length()
    Thread.sleep(2000)
    if (file.length() != size1) {
        ec.logger.info("Skipping ${file.name} — still being written")
        return
    }

    def content = file.text
    // Support batch files: split on {1: block starts
    def messages = content.contains("{1:") ?
        content.split("(?=\\{1:)").findAll { it.trim() } : [content]

    def hasSuccess = false
    def hasDup = false

    messages.each { msgContent ->
        def result = ec.service.sync()
            .name("trade.swift.InboundSwiftServices.ingest#SwiftMessage")
            .parameters([rawContent: msgContent.trim(),
                         sourceChannel: "SRC_DIRECTORY_POLL",
                         sourceFileName: file.name]).call()

        if (result.isDuplicate) {
            hasDup = true
        } else if (result.parseSuccess) {
            hasSuccess = true
        }
    }

    // Move file to processed (or error if all failed, or duplicate)
    def targetDir = processedDir
    if (!hasSuccess && hasDup) targetDir = duplicateDir
    else if (!hasSuccess && !hasDup) targetDir = errorDir

    file.renameTo(new File(targetDir, file.name))
}
